+fn write_jsonl_file<T: Serialize>(path: &Path, values: &[T]) -> ArtifactTestResult<()> {
+    let mut jsonl = String::new();
+    for value in values {
+        jsonl.push_str(&serde_json::to_string(value)?);
+        jsonl.push('\n');
+    }
+    fs::write(path, jsonl)?;
+    Ok(())
