+fn read_jsonl_file<T>(path: &Path) -> ArtifactTestResult<Vec<T>>
+where
+    T: for<'de> Deserialize<'de>,
+{
+    let raw = fs::read_to_string(path)?;
+    raw.lines()
+        .filter(|line| !line.trim().is_empty())
+        .map(|line| serde_json::from_str::<T>(line).map_err(Into::into))
+        .collect()
